query:
-- Active subscriptions by plan
SELECT plan, COUNT(*) as count, status FROM subscriptions GROUP BY plan, status ORDER BY plan;

-- Credit top-up revenue (amountPaid is in pence)
SELECT 
  packName,
  COUNT(*) as purchases,
  SUM(creditsAdded) as total_credits_sold,
  SUM(amountPaid) / 100.0 as revenue_gbp
FROM topupPurchases
GROUP BY packName
ORDER BY revenue_gbp DESC;

-- Total top-up revenue
SELECT COUNT(*) as total_topups, SUM(amountPaid)/100.0 as total_topup_revenue_gbp FROM topupPurchases;

-- Credit usage breakdown
SELECT type, COUNT(*) as count, SUM(ABS(amount)) as total_credits FROM creditTransactions GROUP BY type;

-- Completed jobs all time
SELECT COUNT(*) as completed_jobs, SUM(totalScenes) as total_scenes FROM musicVideoJobs WHERE status = 'completed';

-- Provider spend (all time)
SELECT provider, COUNT(*) as calls, SUM(estimatedCostUsd) as estimated_cost_usd FROM providerJobLogs GROUP BY provider;

